class DirectedGraph:
    """有向图：检测环（拓扑排序应用）"""
    def __init__(self, num_vertices):
        self.V = num_vertices
        self.adj = [[] for _ in range(num_vertices)]

    def add_edge(self, u, v):
        self.adj[u].append(v)  # 仅单向添加

    def has_cycle(self):
        """使用三色标记法检测有向图环"""
        WHITE, GRAY, BLACK = 0, 1, 2
        color = [WHITE] * self.V

        def dfs(node):
            color[node] = GRAY  # 正在访问
            for neighbor in self.adj[node]:
                if color[neighbor] == GRAY:   # 遇到回边
                    return True
                if color[neighbor] == WHITE and dfs(neighbor):
                    return True
            color[node] = BLACK  # 访问完成
            return False

        for i in range(self.V):
            if color[i] == WHITE and dfs(i):
                return True
        return False

# 示例：课程依赖 0->1->2 (无环)
dg = DirectedGraph(3)
dg.add_edge(0, 1)
dg.add_edge(1, 2)
print(dg.has_cycle())  # False

# 邻接矩阵实现稠密图（如完全图）
class DenseGraph:
    def __init__(self, n):
        self.matrix = [[0] * n for _ in range(n)]
        self.n = n

    def add_edge(self, u, v, weight=1):
        self.matrix[u][v] = weight  # 有向图
        # self.matrix[v][u] = weight  # 若为无向图则对称添加

    def get_neighbors(self, u):
        """返回顶点 u 的所有邻居"""
        return [v for v in range(self.n) if self.matrix[u][v] != 0]

